// 获取插件版本方法
export function getPluginVersion() {
  return cepSpy.extVersion;
}
// 获取插件版本方法
export function getTenantId() {
  // cep-spy 初始化时已自动读取 package.json，直接取即可
  const pkg = cepSpy.package;
  console.error('版本:', pkg.id);
  return pkg.id; // 插件版本来自 manifest.xml
}
